library(lubridate)
library(forcats)

wildschwein_BE_annotated &lt;- wildschwein_BE_annotated |&gt;
  mutate(
    DatetimeUTC = ymd_hms(DatetimeUTC),
    hour = hour(DatetimeUTC),
    Frucht = if_else(is.na(Frucht), "No field / unknown", Frucht)
  )

crop_hour_counts &lt;- wildschwein_BE_annotated |&gt;
  st_drop_geometry() |&gt;
  count(hour, Frucht, name = "n")


most_common_fruits &lt;- wildschwein_BE_annotated |&gt;
  st_drop_geometry() |&gt;
  count(Frucht, sort = TRUE) |&gt;
  slice_head(n = 5) |&gt;
  pull(Frucht)

crop_hour_percent &lt;- crop_hour_counts |&gt;
  filter(Frucht %in% most_common_fruits) |&gt;
  group_by(hour) |&gt;
  mutate(percent = n / sum(n) * 100) |&gt;
  ungroup()


ggplot(crop_hour_percent, aes(x = hour, y = percent, fill = Frucht)) +
  geom_col(position = "stack") +
  scale_x_continuous(breaks = 0:23) +
  labs(
    title = "Percentage of wild boar samples per crop type and hour",
    x = "Hour of day",
    y = "Percentage of samples",
    fill = "Crop / land-use type"
  ) +
  theme_minimal()









