crop_hour_animal &lt;- wildschwein_BE_annotated |&gt;
  st_drop_geometry() |&gt;
  filter(Frucht %in% most_common_fruits) |&gt;
  count(TierName, hour, Frucht, name = "n") |&gt;
  group_by(TierName, hour) |&gt;
  mutate(percent = n / sum(n) * 100) |&gt;
  ungroup()

ggplot(crop_hour_animal, aes(x = hour, y = percent, fill = Frucht)) +
  geom_col(position = "stack") +
  facet_wrap(~ TierName) +
  scale_x_continuous(breaks = seq(0, 23, by = 4)) +
  labs(
    title = "Crop use by hour and individual wild boar",
    x = "Hour of day",
    y = "Percentage of samples",
    fill = "Crop / land-use type"
  ) +
  theme_minimal()
